import React from 'react';

const Footer = () => {
  return (
    <footer id="contact" className='footerdoSite'>
      <p>&copy; 2026 Meu Portifólio. Creditos: João Soares | github/devjoaosoares.</p>
      <a href="https://github.com/devjoaosoares/MeuPortifolioWeb.git">Source Code</a>
      <a href="https://www.linkedin.com/in/jo%C3%A3o-vitor-alves-soares-190012283/">LinkedIn</a>
      <a href="https://github.com/devjoaosoares">GitHub</a>
    </footer>
  );
};

export default Footer;
